"use client"

import * as React from "react"
import { Progress as ProgressPrimitive } from "@ark-ui/react/progress"

import { cn } from "@/registry/ark-maia/lib/utils"

function Progress({
  className,
  value,
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Root>) {
  return (
    <ProgressPrimitive.Root
      data-slot="progress"
      className={cn("h-3 rounded-4xl bg-muted", className)}
      value={value}
      {...props}
    >
      <ProgressPrimitive.Track className="h-3 rounded-4xl bg-muted">
        <ProgressPrimitive.Range className="" />
      </ProgressPrimitive.Track>
    </ProgressPrimitive.Root>
  )
}

const ProgressContext = ProgressPrimitive.Context
const ProgressRootProvider = ProgressPrimitive.RootProvider

export { Progress, ProgressContext, ProgressRootProvider }
export {
  useProgress,
  useProgressContext,
  type ProgressValueChangeDetails,
} from "@ark-ui/react/progress"
